mapper.select:
SELECT t.id AS id, t.game_id AS gameId, t.game_name AS gameName, t.venue_name AS venueName, t.venue_type AS venueType, t.status AS status, CASE WHEN t1.site_code IS NOT NULL AND t1.site_code != '' THEN t1.created_time ELSE t.updated_time END AS operatorTime,
CASE WHEN t1.site_code IS NOT NULL AND t1.site_code != '' THEN t1.creator ELSE t.creator END AS operator,
CASE WHEN t.id = t1.game_info_id THEN 1 ELSE 0 END AS chooseFlag
FROM game_info t LEFT JOIN site_game t1 ON t.id = t1.game_info_id AND t1.site_code = #{vo.siteCode} WHERE t.venue_code = #{vo.venueCode}
AND t.game_name = #{vo.gameName}
AND t.game_id = #{vo.gameId}
AND t.status = #{vo.status}
ORDER BY chooseFlag desc, t.status ASC, t.updated_time DESC, t.id DESC

mapper.sql:
SELECT * FROM (SELECT info.`id`, info.`game_id`, info.`game_i18n_code`, info.`venue_code`, s_g.`status`, info.`icon_i18n_code`, info.`se_icon_i18n_code`, info.`vt_icon_i18n_code`, info.`ht_icon_i18n_code`, info.`game_desc_i18n_code`, info.`access_parameters`, s_g.`maintenance_start_time`, s_g.`maintenance_end_time`, s_g.label as label, s_g.corner_labels as cornerLabels, s_g.creator as creator, s_g.created_time as createdTime, s_g.updater as updater, s_g.updated_time as updatedTime, s_g.currency_code, two_sort.sort, tw_info.id as gameTwoId, ifnull (tw_info.sort ,100) as classTwoSort, tw_info.icon as classTwoIcon, tw_info.type_i18n_code as gameTwoClassName, two_sort.game_one_hot_sort FROM site_game s_g
INNER JOIN game_info info ON s_g.game_info_id = info.id
INNER JOIN game_two_currency_sort two_sort ON two_sort.game_id = s_g.game_info_id
INNER JOIN game_two_class_info tw_info ON tw_info.id = two_sort.game_two_id and tw_info.`status` = 1
where s_g.site_code = #{siteCode} and s_g.currency_code LIKE CONCAT('%', #{requestVO.currencyCode}, '%')
and s_g.`status` in (1, 2) and two_sort.currency_code = #{requestVO.currencyCode}
and s_g.label = #{requestVO.label}
and tw_info.id = #{requestVO.gameTwoId}
and two_sort.game_one_id = #{requestVO.gameOneId}
AND info.game_i18n_code IN
#{item}
AND info.id IN
#{id}
) tb GROUP BY tb.id ORDER BY tb.sort

mapper.select:
SELECT info.`id`, info.`game_id`, info.`game_i18n_code`, info.`venue_code`, s_g.`status`, info.`icon_i18n_code`, info.`se_icon_i18n_code`, info.`vt_icon_i18n_code`, info.`ht_icon_i18n_code`, info.`game_desc_i18n_code`, info.`access_parameters`, s_g.`maintenance_start_time`, s_g.`maintenance_end_time`, s_g.label as label, s_g.corner_labels as cornerLabels, s_g.creator as creator, s_g.created_time as createdTime, s_g.updater as updater, s_g.updated_time as updatedTime, s_g.currency_code, two_sort.sort, tw_info.id as gameTwoId, ifnull (tw_info.sort ,100) as classTwoSort, tw_info.icon as classTwoIcon, tw_info.type_i18n_code as gameTwoClassName, two_sort.game_one_hot_sort FROM site_game s_g
INNER JOIN game_info info ON s_g.game_info_id = info.id
INNER JOIN game_two_currency_sort two_sort ON two_sort.game_id = s_g.game_info_id and two_sort.currency_code = #{currencyCode}
INNER JOIN game_two_class_info tw_info ON tw_info.id = two_sort.game_two_id and tw_info.`status` = 1
where s_g.site_code = #{siteCode} and s_g.currency_code LIKE CONCAT('%', #{currencyCode}, '%') and s_g.`status` in (1, 2)
and two_sort.game_one_id = #{gameOneId}

SELECT * FROM (SELECT
ifnull(hot.home_hot_sort, 100) as homeHotSort, two_sort.game_one_hot_sort as gameOneHotSort, info.`id`, info.`game_name`, info.`game_i18n_code`, info.`venue_code`, s_g.`status` FROM site_game s_g
INNER JOIN game_info info ON s_g.game_info_id = info.id
INNER JOIN game_two_currency_sort two_sort ON two_sort.game_id = s_g.game_info_id and two_sort.currency_code = #{currencyCode}
INNER JOIN game_two_class_info tw_info ON tw_info.id = two_sort.game_two_id and tw_info.`status` = 1
LEFT JOIN site_game_hot_sort hot ON hot.game_id = info.id and hot.site_code = #{siteCode}
where s_g.site_code = #{siteCode} and s_g.currency_code LIKE CONCAT('%', #{currencyCode}, '%') and s_g.`status` in (1, 2)
and two_sort.game_one_id = #{gameOneId}
and s_g.label = 1) t GROUP BY t.id

