select g_info.id,g_info.game_name, g_info.game_i18n_code, g_info.game_id,s_game.`status`, s_game.label,s_game.corner_labels, s_game.currency_code, g_info.ht_icon_i18n_code, g_info.se_icon_i18n_code, g_info.vt_icon_i18n_code, g_info.icon_i18n_code, g_info.venue_name, s_game.maintenance_start_time, s_game.maintenance_end_time, s_game.remark, s_game.venue_code, s_game.updater, s_game.updated_time, g_info.access_parameters
